import{_ as l,o as r,c as i,ae as t}from"./chunks/framework.CbfcRfVi.js";const c=JSON.parse('{"title":"Finishing up","description":"","frontmatter":{},"headers":[],"relativePath":"ps4/ending.md","filePath":"ps4/ending.md","lastUpdated":1777872142000}'),a={name:"ps4/ending.md"};function o(n,e,s,h,u,d){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="finishing-up" tabindex="-1">Finishing up <a class="header-anchor" href="#finishing-up" aria-label="Permalink to &quot;Finishing up&quot;">​</a></h1><p>And you&#39;re done! If this guide was helpful, you can star it on GitHub and share it!</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>I highly recommend continuing to the <a href="/playstation-linux-tutorial/post-install.html">&quot;Post Installation&quot; setup</a>, to change language and setup better memory management!</p></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>For any problems, <a href="/playstation-linux-tutorial/issues.html">check the issues page</a>!</p></div><h2 id="credits" tabindex="-1">Credits <a class="header-anchor" href="#credits" aria-label="Permalink to &quot;Credits&quot;">​</a></h2><h2 id="big-credits-to-dionkill-for-keeping-the-original-guide-updated" tabindex="-1">Big credits to DionKill for keeping the original guide updated. <a class="header-anchor" href="#big-credits-to-dionkill-for-keeping-the-original-guide-updated" aria-label="Permalink to &quot;Big credits to DionKill for keeping the original guide updated.&quot;">​</a></h2><h3 id="kernel-developers" tabindex="-1">Kernel developers <a class="header-anchor" href="#kernel-developers" aria-label="Permalink to &quot;Kernel developers&quot;">​</a></h3><p>These are the original kernel developers, who did the hard work to port the kernels on which all of the modern kernels are based on. None of this would&#39;ve been possible without them.</p><ul><li>4.4 kernel <ul><li>marcan, fail0verflow team</li></ul></li><li>4.14 kernel <ul><li>rancido, and psxitateam, eeply, valery for Baikal (based on fail0verflow)</li></ul></li><li>4.19 and 5.3 kernel <ul><li>mircoho, (based on fail0verflow, psxitateam, eeply, valeryy)</li></ul></li><li>5.15 kernel <ul><li>codedwrench (based on fail0verflow, psxitateam, eeply, valeryy, mircoho)</li></ul></li><li>6.15 kernel <ul><li>crashniels with 2 patches from mircoho (fastboot and ethernet kp fixes) (based on fail0verflow - psxitateam - eeply - valeryy - mircoho - codedwrench)</li></ul></li></ul><p>If you want, you can check out their repos:</p><ul><li><a href="https://github.com/fail0verflow/ps4-linux" target="_blank" rel="noreferrer">marcan (fail0verflow) </a><ul><li>Without them nothing would&#39;ve ever been possible.</li></ul></li><li><a href="https://github.com/Ps3itaTeam/ps4-linux/" target="_blank" rel="noreferrer">rancido (psxitateam)</a><ul><li>Made the AMDGPU driver work.</li></ul></li><li><a href="https://github.com/eeply/ps4-linux" target="_blank" rel="noreferrer">eeply</a><ul><li>Brought PS4 Pro to work for video output, in fact now all ps4 with new Panasonic HDMI chip work.</li></ul></li><li>valeryy (no GitHub, gave the code to rancido) <ul><li>Brought the Baikal Southbridge support.</li></ul></li><li><a href="https://github.com/tihmstar/ps4-linux" target="_blank" rel="noreferrer">tihmstar</a><ul><li>Brought the Internal SATA driver for PS4 Belize.</li></ul></li><li><a href="https://github.com/ps4boot/ps4-linux" target="_blank" rel="noreferrer">mircoho</a> (<a href="https://github.com/ps4gentoo/ps4-linux-5.3.7" target="_blank" rel="noreferrer">ps4gentoo</a> and <a href="https://github.com/ps4boot/" target="_blank" rel="noreferrer">ps4boot</a>) <ul><li>Worked on the kernel (especially Gentoo), ported payloads to newer firmwares.</li></ul></li><li><a href="https://github.com/codedwrench/ps4-linux" target="_blank" rel="noreferrer">codedwrench</a><ul><li>Made kernel patches.</li></ul></li><li><a href="https://github.com/crashniels/linux" target="_blank" rel="noreferrer">crashniels</a><ul><li>Ported newer kernel versions.</li></ul></li><li><a href="https://github.com/feeRnt/ps4-linux-12xx" target="_blank" rel="noreferrer">feeRnt</a> (Package) <ul><li>Hosts and maintains the PS4 Linux kernel sources on GitHub.</li></ul></li></ul><h3 id="additional-credits" tabindex="-1">Additional credits <a class="header-anchor" href="#additional-credits" aria-label="Permalink to &quot;Additional credits&quot;">​</a></h3><ul><li><a href="https://www.youtube.com/@saya7068" target="_blank" rel="noreferrer">saya</a><ul><li>For their great kernels and tutorials.</li></ul></li><li><a href="https://www.youtube.com/channel/UCU-eXjZ7Ud0k2wC_14mqdOw" target="_blank" rel="noreferrer">Qba</a><ul><li>For their constant updates and new distros.</li></ul></li><li><a href="https://www.youtube.com/@trakerchris9876" target="_blank" rel="noreferrer">triki1</a><ul><li>For their kernel and tutorials, distros and Mesa updaters.</li></ul></li><li><a href="https://uar.no/ps4/" target="_blank" rel="noreferrer">uar</a><ul><li>For their tutorial and fixes for baikal consoles and more.</li></ul></li><li><a href="https://github.com/centi07/" target="_blank" rel="noreferrer">centi07</a><ul><li>For their help with up-to-date mesa package repos on Arch and more.</li></ul></li></ul><p>Thank you all so much for making this possible.</p>',14)])])}const f=l(a,[["render",o]]);export{c as __pageData,f as default};
